import React from 'react'
import '../css/results.css'
import { useSelector,useDispatch } from 'react-redux'

export default function Results() {
  
  const journey_details=useSelector((state)=>state.var.journey_inf)
  const train_details=useSelector((state)=>state.var.train)


  return (
    <>
      <div className='results'>
        
        <section className='container-1'>
           <div className='left-image'>
                <div className='train-image'>
                  <img src="https://eticket.railway.gov.bd/assets/img/train-app/running-train-icon.svg" alt="" />
                </div>
           </div>

        </section>

      </div>
    </>
  )
}
